#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define HEATER_PIN 9
#define STIRRER_PIN 7
#define OW_PIN 2
#define SD_CS 10
#define SETPOINT 45.0f
#define KP 8.0f
#define KI 0.4f
#define KD 1.2f
#define FAULT_TEMP 80.0f
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
float g_intg=0, g_lastE=0;
int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float*intg,float*lastE){
  float e=sp-pv;
  *intg=constrain(*intg+e*dt,-100.0f,100.0f);
  float d=(e-*lastE)/max(dt,0.001f); *lastE=e;
  return constrain((int)(kp*e+ki*(*intg)+kd*d),0,255);
}
void initHardware(){
  pinMode(HEATER_PIN,OUTPUT); pinMode(STIRRER_PIN,OUTPUT);
  ds.begin(); SD.begin(SD_CS);
  lg=SD.open("log.csv",FILE_WRITE);
  if(lg) lg.println("t_s,T_C,pwm");
  digitalWrite(STIRRER_PIN,HIGH); Serial.begin(9600);
}
float readTemperatureSensor(){
  ds.requestTemperatures(); return ds.getTempCByIndex(0);
}
void logDataSD(unsigned long t, float T, int pwm){
  if(lg){lg.print(t);lg.print(',');lg.print(T,2);lg.print(',');lg.println(pwm);lg.flush();}
  Serial.print("T=");Serial.print(T,2);Serial.print(" PWM=");Serial.println(pwm);
}
void checkFaultSafety(float T){
  if(T>FAULT_TEMP){
    analogWrite(HEATER_PIN,0); digitalWrite(STIRRER_PIN,LOW);
    if(lg) lg.println("FAULT:OVERTEMP");
    Serial.println("FAULT:OVERTEMP"); while(1);
  }
}
void setup(){ initHardware(); }
void loop(){
  static unsigned long prev=0; unsigned long now=millis();
  float dt=(now-prev)/1000.0f; if(dt<1.0f) return; prev=now;
  float T=readTemperatureSensor(); checkFaultSafety(T);
  int pwm=pid_heater_control(SETPOINT,T,dt,KP,KI,KD,&g_intg,&g_lastE);
  analogWrite(HEATER_PIN,pwm); logDataSD(now/1000,T,pwm);
}
